SELECT COUNT(*) AS total_species
FROM bird_species
WHERE conservation_status = 'VU';

SELECT conservation_status, COUNT(*) AS species_count
FROM bird_species
GROUP BY conservation_status;

SELECT species_name, common_name, conservation_status, population_trend
FROM bird_species
WHERE species_id = 0;

SELECT feather_color
FROM physical_characteristics
WHERE species_id = 0;
